Using the default DocumentBuilder configuration is extremely dangerous and leaves your application vulnerable to XXE (XML External Entity) attacks, including SSRF (Server-Side Request Forgery). The 2023 Ivanti breach (CVE-2023-35078) demonstrated how attackers can exploit XXE to steal cloud credentials and pivot through internal networks.

**VULNERABLE CODE**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.InputStream;

public class XmlUploadServlet extends javax.servlet.http.HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        try {
            InputStream xmlInput = request.getInputStream();

            // VULNERABLE: Default DocumentBuilder allows external entities
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();

            // This parses user-controlled XML without any protection
            Document document = builder.parse(xmlInput);

            NodeList items = document.getElementsByTagName("item");
            response.getWriter().write("Parsed " + items.getLength() + " items");

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
```

**Attack Payload - SSRF to AWS Metadata**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE data [
  <!ENTITY xxe SYSTEM "http://169.254.169.254/latest/meta-data/iam/security-credentials/">
]>
<data>
  <item>&xxe;</item>
</data>
```

**Attack Payload - Internal Port Scanning**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE data [
  <!ENTITY xxe SYSTEM "http://internal-database:3306/">
]>
<data>
  <item>&xxe;</item>
</data>
```

**Why This Is Dangerous**:
- Default XML parsers resolve external entities, allowing attackers to make HTTP requests from your server
- SSRF attacks can access cloud metadata endpoints (169.254.169.254) to steal IAM credentials
- Attackers can scan internal networks and access services behind firewalls
- Response-based XXE leaks internal data back to the attacker
- Can chain with other vulnerabilities for full infrastructure compromise

**SECURE VERSION**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.XMLConstants;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.InputStream;
import java.util.logging.Logger;
import java.util.logging.Level;

public class SecureXmlUploadServlet extends javax.servlet.http.HttpServlet {

    private static final Logger LOGGER = Logger.getLogger(SecureXmlUploadServlet.class.getName());
    private static final int MAX_XML_SIZE = 1024 * 1024; // 1MB limit

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        try {
            // Defense 1: Size limit to prevent DoS
            if (request.getContentLength() > MAX_XML_SIZE) {
                response.sendError(HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE);
                return;
            }

            InputStream xmlInput = request.getInputStream();

            // Defense 2: Secure DocumentBuilder configuration
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

            // Disable external entities completely
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            // Defense 3: Set secure processing mode
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(xmlInput);

            NodeList items = document.getElementsByTagName("item");

            LOGGER.info("Successfully parsed XML with " + items.getLength() + " items");
            response.getWriter().write("Parsed " + items.getLength() + " items");

        } catch (Exception e) {
            LOGGER.log(Level.WARNING, "XML parsing failed", e);
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
        }
    }
}
```

**Key Security Controls**:
- **Disable DOCTYPE declarations**: `disallow-doctype-decl` prevents all entity declarations including XXE
- **Disable external entities**: Explicitly blocks both general and parameter external entities
- **Secure processing mode**: Enables additional security restrictions in the parser
- **Block external DTD/Schema access**: Prevents loading remote DTD files that could contain entity definitions

For production environments handling SOAP services and needing protection against blind/out-of-band XXE attacks, you need a comprehensive defense strategy. Blind XXE doesn't return data directly but exfiltrates it via DNS lookups or HTTP requests to attacker-controlled servers.

**PRODUCTION PATTERN**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;
import javax.xml.XMLConstants;
import javax.xml.transform.stream.StreamSource;
import javax.xml.validation.Schema;
import javax.xml.validation.SchemaFactory;
import javax.xml.validation.Validator;
import org.w3c.dom.Document;
import org.xml.sax.SAXException;
import org.xml.sax.InputSource;
import java.io.*;
import java.util.logging.Logger;
import java.util.logging.Level;
import java.util.concurrent.*;
import java.security.MessageDigest;
import java.util.Base64;

public class SecureXmlProcessor {

    private static final Logger LOGGER = Logger.getLogger(SecureXmlProcessor.class.getName());
    private static final Logger SECURITY_AUDIT = Logger.getLogger("SECURITY_AUDIT");

    private static final int MAX_XML_SIZE = 5 * 1024 * 1024; // 5MB
    private static final int MAX_ENTITY_EXPANSIONS = 100;
    private static final int PARSE_TIMEOUT_SECONDS = 30;

    private final DocumentBuilderFactory documentBuilderFactory;
    private final SAXParserFactory saxParserFactory;
    private final ExecutorService parseExecutor;

    public SecureXmlProcessor() {
        this.documentBuilderFactory = createSecureDocumentBuilderFactory();
        this.saxParserFactory = createSecureSAXParserFactory();
        this.parseExecutor = Executors.newFixedThreadPool(4);
    }

    /**
     * Creates a fully hardened DocumentBuilderFactory
     */
    private DocumentBuilderFactory createSecureDocumentBuilderFactory() {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        try {
            // Layer 1: Completely disable DOCTYPE declarations (strongest protection)
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

            // Layer 2: Disable all external entity processing
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

            // Layer 3: Disable XInclude processing (another attack vector)
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            // Layer 4: Enable secure processing mode
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

            // Layer 5: Block all external access
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            LOGGER.info("Secure DocumentBuilderFactory initialized");

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to configure secure XML parser", e);
            throw new RuntimeException("Cannot initialize secure XML parser", e);
        }

        return factory;
    }

    /**
     * Creates a hardened SAXParserFactory for streaming XML processing
     */
    private SAXParserFactory createSecureSAXParserFactory() {
        SAXParserFactory factory = SAXParserFactory.newInstance();

        try {
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            factory.setXIncludeAware(false);

        } catch (Exception e) {
            throw new RuntimeException("Cannot initialize secure SAX parser", e);
        }

        return factory;
    }

    /**
     * Parse XML with comprehensive security controls and timeout protection
     */
    public Document parseXmlSecurely(InputStream xmlInput, String sourceIdentifier, String clientIp) 
            throws XmlSecurityException {

        // Pre-processing security checks
        byte[] xmlBytes;
        try {
            xmlBytes = readWithSizeLimit(xmlInput, MAX_XML_SIZE);
        } catch (IOException e) {
            SECURITY_AUDIT.warning(String.format(
                "XML_SIZE_EXCEEDED|source=%s|ip=%s", sourceIdentifier, clientIp));
            throw new XmlSecurityException("XML payload too large");
        }

        // Log input hash for forensics (not the content)
        String inputHash = computeHash(xmlBytes);
        SECURITY_AUDIT.info(String.format(
            "XML_PARSE_START|source=%s|ip=%s|size=%d|hash=%s",
            sourceIdentifier, clientIp, xmlBytes.length, inputHash));

        // Quick scan for suspicious patterns (defense in depth)
        if (containsSuspiciousPatterns(xmlBytes)) {
            SECURITY_AUDIT.warning(String.format(
                "XXE_PATTERN_DETECTED|source=%s|ip=%s|hash=%s",
                sourceIdentifier, clientIp, inputHash));
            throw new XmlSecurityException("Potentially malicious XML content detected");
        }

        // Parse with timeout to prevent billion laughs DoS
        Future<Document> parseTask = parseExecutor.submit(() -> {
            DocumentBuilder builder = documentBuilderFactory.newDocumentBuilder();
            return builder.parse(new ByteArrayInputStream(xmlBytes));
        });

        try {
            Document document = parseTask.get(PARSE_TIMEOUT_SECONDS, TimeUnit.SECONDS);

            SECURITY_AUDIT.info(String.format(
                "XML_PARSE_SUCCESS|source=%s|ip=%s|hash=%s",
                sourceIdentifier, clientIp, inputHash));

            return document;

        } catch (TimeoutException e) {
            parseTask.cancel(true);
            SECURITY_AUDIT.severe(String.format(
                "XML_PARSE_TIMEOUT|source=%s|ip=%s|hash=%s|potential_dos=true",
                sourceIdentifier, clientIp, inputHash));
            throw new XmlSecurityException("XML parsing timeout - potential DoS attack");

        } catch (ExecutionException e) {
            SECURITY_AUDIT.warning(String.format(
                "XML_PARSE_FAILED|source=%s|ip=%s|error=%s",
                sourceIdentifier, clientIp, e.getCause().getMessage()));
            throw new XmlSecurityException("XML parsing failed", e.getCause());

        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new XmlSecurityException("XML parsing interrupted");
        }
    }

    /**
     * Pattern-based detection for XXE attempts (defense in depth)
     */
    private boolean containsSuspiciousPatterns(byte[] xmlBytes) {
        String content = new String(xmlBytes).toLowerCase();

        // Detect entity declarations
        if (content.contains("<!entity")) {
            return true;
        }

        // Detect SYSTEM or PUBLIC keywords in DOCTYPE
        if (content.contains("<!doctype") && 
            (content.contains("system") || content.contains("public"))) {
            return true;
        }

        // Detect common SSRF targets
        String[] ssrfTargets = {
            "169.254.169.254",      // AWS metadata
            "metadata.google",       // GCP metadata
            "metadata.azure",        // Azure metadata
            "localhost",
            "127.0.0.1",
            "[::1]",
            "file://",
            "gopher://",
            "dict://",
            "php://",
            "expect://"
        };

        for (String target : ssrfTargets) {
            if (content.contains(target)) {
                return true;
            }
        }

        // Detect parameter entity declarations (blind XXE)
        if (content.contains("% ") && content.contains("<!entity")) {
            return true;
        }

        return false;
    }

    /**
     * Read input stream with size limit
     */
    private byte[] readWithSizeLimit(InputStream input, int maxSize) throws IOException {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        byte[] chunk = new byte[8192];
        int bytesRead;
        int totalRead = 0;

        while ((bytesRead = input.read(chunk)) != -1) {
            totalRead += bytesRead;
            if (totalRead > maxSize) {
                throw new IOException("Input exceeds maximum allowed size");
            }
            buffer.write(chunk, 0, bytesRead);
        }

        return buffer.toByteArray();
    }

    private String computeHash(byte[] data) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(data);
            return Base64.getEncoder().encodeToString(hash).substring(0, 16);
        } catch (Exception e) {
            return "hash-error";
        }
    }

    /**
     * SOAP-specific secure parsing with schema validation
     */
    public Document parseSoapEnvelope(InputStream soapInput, InputStream schemaInput,
                                       String serviceId, String clientIp) 
            throws XmlSecurityException {

        byte[] soapBytes;
        try {
            soapBytes = readWithSizeLimit(soapInput, MAX_XML_SIZE);
        } catch (IOException e) {
            throw new XmlSecurityException("SOAP envelope too large");
        }

        // Validate against schema first (prevents malformed input)
        try {
            SchemaFactory schemaFactory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);
            schemaFactory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            schemaFactory.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            schemaFactory.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            Schema schema = schemaFactory.newSchema(new StreamSource(schemaInput));
            Validator validator = schema.newValidator();
            validator.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            validator.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            validator.validate(new StreamSource(new ByteArrayInputStream(soapBytes)));

        } catch (SAXException e) {
            SECURITY_AUDIT.warning(String.format(
                "SOAP_SCHEMA_VALIDATION_FAILED|service=%s|ip=%s|error=%s",
                serviceId, clientIp, e.getMessage()));
            throw new XmlSecurityException("SOAP envelope failed schema validation");
        } catch (Exception e) {
            throw new XmlSecurityException("Schema validation error", e);
        }

        // Parse the validated SOAP envelope
        return parseXmlSecurely(new ByteArrayInputStream(soapBytes), serviceId, clientIp);
    }

    public void shutdown() {
        parseExecutor.shutdown();
    }

    /**
     * Custom exception for XML security violations
     */
    public static class XmlSecurityException extends Exception {
        public XmlSecurityException(String message) {
            super(message);
        }

        public XmlSecurityException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
```

**Defense in Depth Layers**:

1. **Parser Hardening** - Disable DOCTYPE, external entities, and XInclude at the parser level:
```java
factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
```

2. **Pattern Detection** - Pre-scan XML for known XXE/SSRF patterns before parsing:
```java
if (content.contains("169.254.169.254") || content.contains("<!entity")) {
    throw new XmlSecurityException("Suspicious content detected");
}
```

3. **Timeout Protection** - Prevent Billion Laughs DoS with parse timeouts:
```java
Document document = parseTask.get(PARSE_TIMEOUT_SECONDS, TimeUnit.SECONDS);
```

**Additional Protections**:

- **Network-level egress filtering**: Block outbound connections to metadata endpoints (169.254.169.254) at firewall level to stop blind XXE even if parser is compromised
- **Schema validation for SOAP**: Validates XML structure against expected schema before processing
- **Security audit logging**: All parse attempts logged with content hashes for forensic analysis
- **Size limits**: Prevents memory exhaustion attacks
- **Separate security audit log**: Makes detection of XXE attempts easier for SOC teams

**Blind XXE Detection Strategy**:
```java
// Monitor for DNS queries to unusual domains
// Alert if server makes unexpected outbound HTTP requests
// Use network monitoring to detect:
// - DNS lookups for attacker-controlled domains
// - HTTP requests to external IPs from XML processing services
// - Unusual egress traffic patterns after XML upload
```

SOAP web services in PHP are highly susceptible to XML External Entity (XXE) attacks when they parse incoming XML requests without proper security configurations. The default PHP XML parsers often have external entity processing enabled, making them vulnerable.

**VULNERABLE CODE**:

```php
<?php
// Vulnerable SOAP service handler
class PaymentService {
    private $db;

    public function __construct($database) {
        $this->db = $database;
    }

    public function processPayment($xmlRequest) {
        // VULNERABLE: Default DOMDocument settings allow XXE
        $dom = new DOMDocument();
        $dom->loadXML($xmlRequest);  // Dangerous: parses external entities

        $xpath = new DOMXPath($dom);
        $xpath->registerNamespace('soap', 'http://schemas.xmlsoap.org/soap/envelope/');
        $xpath->registerNamespace('pay', 'http://payment.example.com/');

        $amount = $xpath->query('//pay:Amount')->item(0)->nodeValue;
        $accountId = $xpath->query('//pay:AccountId')->item(0)->nodeValue;

        return $this->executePayment($accountId, $amount);
    }

    private function executePayment($accountId, $amount) {
        // Payment processing logic
        return "Payment of $amount processed for account $accountId";
    }
}

// Handle incoming SOAP request
$rawPost = file_get_contents('php://input');
$service = new PaymentService($pdo);
echo $service->processPayment($rawPost);
```

**Attack Payload**:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE soap:Envelope [
  <!ENTITY xxe SYSTEM "file:///etc/passwd">
  <!ENTITY xxe2 SYSTEM "php://filter/convert.base64-encode/resource=/var/www/html/config.php">
]>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/"
               xmlns:pay="http://payment.example.com/">
  <soap:Body>
    <pay:ProcessPayment>
      <pay:Amount>100.00</pay:Amount>
      <pay:AccountId>&xxe;</pay:AccountId>
    </pay:ProcessPayment>
  </soap:Body>
</soap:Envelope>
```

**Why This Is Dangerous**:
- `DOMDocument::loadXML()` processes external entities by default in older PHP versions
- Attackers can read arbitrary files from the server filesystem
- PHP filter wrappers allow base64-encoded file exfiltration, bypassing binary file limitations
- SSRF attacks can probe internal network services via `http://` or `gopher://` URIs

**SECURE VERSION**:

```php
<?php
// Secure SOAP service handler with XXE protection
class SecurePaymentService {
    private $db;
    private $logger;

    public function __construct(PDO $database, $logger) {
        $this->db = $database;
        $this->logger = $logger;
    }

    public function processPayment(string $xmlRequest): string {
        // SECURITY: Disable external entity loading globally
        libxml_disable_entity_loader(true);

        // SECURITY: Use secure libxml options
        $dom = new DOMDocument();
        $dom->resolveExternals = false;
        $dom->substituteEntities = false;

        // SECURITY: Suppress errors and use secure parsing flags
        $previousUseErrors = libxml_use_internal_errors(true);

        $loadOptions = LIBXML_NONET | LIBXML_NOENT | LIBXML_DTDLOAD | LIBXML_DTDATTR;
        // LIBXML_NONET - Disable network access
        // LIBXML_NOENT - Do not substitute entities

        $loaded = $dom->loadXML($xmlRequest, LIBXML_NONET | LIBXML_NOENT);

        if (!$loaded) {
            $errors = libxml_get_errors();
            libxml_clear_errors();
            libxml_use_internal_errors($previousUseErrors);
            $this->logger->warning('Invalid XML received', ['errors' => $errors]);
            throw new InvalidArgumentException('Invalid XML format');
        }

        libxml_use_internal_errors($previousUseErrors);

        // SECURITY: Validate against known schema
        if (!$this->validateSOAPEnvelope($dom)) {
            throw new InvalidArgumentException('Invalid SOAP envelope structure');
        }

        $xpath = new DOMXPath($dom);
        $xpath->registerNamespace('soap', 'http://schemas.xmlsoap.org/soap/envelope/');
        $xpath->registerNamespace('pay', 'http://payment.example.com/');

        $amountNode = $xpath->query('//pay:Amount')->item(0);
        $accountNode = $xpath->query('//pay:AccountId')->item(0);

        if (!$amountNode || !$accountNode) {
            throw new InvalidArgumentException('Missing required payment fields');
        }

        // SECURITY: Validate and sanitize extracted values
        $amount = $this->validateAmount($amountNode->nodeValue);
        $accountId = $this->validateAccountId($accountNode->nodeValue);

        $this->logger->info('Payment request processed', [
            'account_id' => $accountId,
            'amount' => $amount,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ]);

        return $this->executePayment($accountId, $amount);
    }

    private function validateSOAPEnvelope(DOMDocument $dom): bool {
        $root = $dom->documentElement;
        return $root && 
               $root->localName === 'Envelope' &&
               $root->namespaceURI === 'http://schemas.xmlsoap.org/soap/envelope/';
    }

    private function validateAmount(string $value): float {
        if (!preg_match('/^\d+(\.\d{1,2})?$/', $value)) {
            throw new InvalidArgumentException('Invalid amount format');
        }
        $amount = (float)$value;
        if ($amount <= 0 || $amount > 1000000) {
            throw new InvalidArgumentException('Amount out of valid range');
        }
        return $amount;
    }

    private function validateAccountId(string $value): string {
        if (!preg_match('/^[A-Z0-9]{8,12}$/', $value)) {
            throw new InvalidArgumentException('Invalid account ID format');
        }
        return $value;
    }

    private function executePayment(string $accountId, float $amount): string {
        // Payment processing with prepared statements
        return "Payment of $amount processed for account $accountId";
    }
}
```

**Key Security Controls**:
- `libxml_disable_entity_loader(true)` globally prevents external entity loading (deprecated in PHP 8.0+ as it's disabled by default)
- `LIBXML_NONET` flag prevents network access during XML parsing
- `LIBXML_NOENT` prevents entity substitution
- `resolveExternals = false` and `substituteEntities = false` provide additional protection
- Input validation on all extracted values prevents secondary injection attacks

PHP's native `SoapServer` class is also vulnerable to XXE attacks because it uses the same underlying libxml library. Additionally, WSDL files themselves can be attack vectors if fetched from untrusted sources. Here's a production-ready approach that secures both the SOAP message parsing and WSDL handling.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

namespace App\Services\SOAP;

use PDO;
use Psr\Log\LoggerInterface;
use SoapServer;
use SoapFault;
use DOMDocument;

class SecureSOAPService {
    private PDO $db;
    private LoggerInterface $logger;
    private array $config;
    private const MAX_REQUEST_SIZE = 1048576; // 1MB max
    private const ALLOWED_IPS = []; // Whitelist for production

    public function __construct(PDO $db, LoggerInterface $logger, array $config) {
        $this->db = $db;
        $this->logger = $logger;
        $this->config = $config;

        // CRITICAL: Disable external entities at earliest opportunity
        $this->configureXMLSecurity();
    }

    private function configureXMLSecurity(): void {
        // PHP < 8.0: Disable entity loader
        if (PHP_VERSION_ID < 80000) {
            libxml_disable_entity_loader(true);
        }

        // Set secure defaults for all libxml operations
        libxml_use_internal_errors(true);
    }

    public function handleRequest(): void {
        try {
            // Layer 1: Request size validation
            $this->validateRequestSize();

            // Layer 2: IP-based access control (if configured)
            $this->validateSourceIP();

            // Layer 3: Rate limiting check
            $this->checkRateLimit();

            // Layer 4: Pre-validate raw XML before SoapServer processes it
            $rawInput = file_get_contents('php://input');
            $this->preValidateXML($rawInput);

            // Layer 5: Initialize SoapServer with security options
            $server = $this->createSecureSoapServer();
            $server->setClass(PaymentHandler::class, $this->db, $this->logger);

            // Layer 6: Capture and sanitize response
            ob_start();
            $server->handle($rawInput);
            $response = ob_get_clean();

            // Layer 7: Audit logging
            $this->logRequest($rawInput, $response);

            header('Content-Type: text/xml; charset=utf-8');
            echo $response;

        } catch (SoapFault $e) {
            $this->handleSoapError($e);
        } catch (\Exception $e) {
            $this->handleGenericError($e);
        }
    }

    private function validateRequestSize(): void {
        $contentLength = (int)($_SERVER['CONTENT_LENGTH'] ?? 0);
        if ($contentLength > self::MAX_REQUEST_SIZE) {
            $this->logger->warning('Oversized SOAP request rejected', [
                'size' => $contentLength,
                'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
            ]);
            throw new SoapFault('Client', 'Request too large');
        }
    }

    private function validateSourceIP(): void {
        if (!empty(self::ALLOWED_IPS)) {
            $clientIP = $_SERVER['REMOTE_ADDR'] ?? '';
            if (!in_array($clientIP, self::ALLOWED_IPS, true)) {
                $this->logger->alert('Unauthorized SOAP access attempt', [
                    'ip' => $clientIP
                ]);
                throw new SoapFault('Client', 'Access denied');
            }
        }
    }

    private function checkRateLimit(): void {
        $clientIP = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
        $cacheKey = "soap_rate:{$clientIP}";

        // Using APCu for rate limiting (Redis recommended for distributed systems)
        if (function_exists('apcu_fetch')) {
            $count = apcu_fetch($cacheKey);
            if ($count === false) {
                apcu_store($cacheKey, 1, 60);
            } elseif ($count > 100) { // 100 requests per minute
                $this->logger->warning('Rate limit exceeded for SOAP service', [
                    'ip' => $clientIP,
                    'count' => $count
                ]);
                throw new SoapFault('Client', 'Rate limit exceeded');
            } else {
                apcu_inc($cacheKey);
            }
        }
    }

    private function preValidateXML(string $xml): void {
        // CRITICAL: Check for XXE attack patterns BEFORE parsing
        $dangerousPatterns = [
            '/<!ENTITY/i',
            '/<!DOCTYPE[^>]*\[/i',
            '/SYSTEM\s+["\'](?:file|php|expect|data|glob|phar|ssh2|rar|ogg|zlib|compress)/i',
            '/PUBLIC\s+["\'][^"]*["\']\s+["\'][^"]*["\']/',
        ];

        foreach ($dangerousPatterns as $pattern) {
            if (preg_match($pattern, $xml)) {
                $this->logger->alert('XXE attack pattern detected', [
                    'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
                    'pattern' => $pattern,
                    'payload_hash' => hash('sha256', $xml)
                ]);
                throw new SoapFault('Client', 'Invalid XML content');
            }
        }

        // Validate XML structure using secure parser
        $dom = new DOMDocument();
        $dom->resolveExternals = false;
        $dom->substituteEntities = false;

        $result = @$dom->loadXML($xml, LIBXML_NONET | LIBXML_NOENT | LIBXML_DTDLOAD);

        if (!$result) {
            $errors = libxml_get_errors();
            libxml_clear_errors();
            $this->logger->warning('Malformed XML in SOAP request', [
                'errors' => array_map(fn($e) => $e->message, $errors)
            ]);
            throw new SoapFault('Client', 'Malformed XML');
        }
    }

    private function createSecureSoapServer(): SoapServer {
        // SECURITY: Use local WSDL file only, never fetch from remote
        $wsdlPath = $this->config['wsdl_path'];

        if (!file_exists($wsdlPath)) {
            throw new \RuntimeException('WSDL file not found');
        }

        // Validate WSDL file integrity (optional: use checksum)
        $expectedHash = $this->config['wsdl_hash'] ?? null;
        if ($expectedHash && hash_file('sha256', $wsdlPath) !== $expectedHash) {
            $this->logger->critical('WSDL file tampering detected');
            throw new \RuntimeException('WSDL integrity check failed');
        }

        $options = [
            'soap_version' => SOAP_1_2,
            'encoding' => 'UTF-8',
            'cache_wsdl' => WSDL_CACHE_DISK, // Cache locally, don't refetch
            'features' => SOAP_SINGLE_ELEMENT_ARRAYS,
            'send_errors' => $this->config['debug'] ?? false,
        ];

        // CRITICAL: Set stream context to block external connections
        $streamContext = stream_context_create([
            'http' => [
                'timeout' => 5,
                'max_redirects' => 0,
            ],
            'ssl' => [
                'verify_peer' => true,
                'verify_peer_name' => true,
            ],
        ]);
        $options['stream_context'] = $streamContext;

        return new SoapServer($wsdlPath, $options);
    }

    private function logRequest(string $request, string $response): void {
        // Sanitize for logging - remove sensitive data
        $sanitizedRequest = preg_replace(
            '/<(Password|CardNumber|CVV)[^>]*>.*?<\/\1>/i',
            '<$1>[REDACTED]</$1>',
            $request
        );

        $this->logger->info('SOAP request processed', [
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
            'request_size' => strlen($request),
            'response_size' => strlen($response),
            'request_hash' => hash('sha256', $request),
        ]);
    }

    private function handleSoapError(SoapFault $e): void {
        $this->logger->error('SOAP fault', [
            'code' => $e->faultcode,
            'message' => $e->getMessage()
        ]);

        header('Content-Type: text/xml; charset=utf-8');
        http_response_code(500);

        // Return sanitized error - don't leak internal details
        echo $this->buildSoapFault(
            'Server',
            $this->config['debug'] ? $e->getMessage() : 'Internal service error'
        );
    }

    private function handleGenericError(\Exception $e): void {
        $this->logger->error('Unexpected error in SOAP service', [
            'exception' => get_class($e),
            'message' => $e->getMessage(),
            'trace' => $e->getTraceAsString()
        ]);

        header('Content-Type: text/xml; charset=utf-8');
        http_response_code(500);
        echo $this->buildSoapFault('Server', 'Service temporarily unavailable');
    }

    private function buildSoapFault(string $code, string $message): string {
        $escapedMessage = htmlspecialchars($message, ENT_XML1, 'UTF-8');
        return <<<XML
<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://www.w3.org/2003/05/soap-envelope">
  <soap:Body>
    <soap:Fault>
      <soap:Code><soap:Value>soap:{$code}</soap:Value></soap:Code>
      <soap:Reason><soap:Text xml:lang="en">{$escapedMessage}</soap:Text></soap:Reason>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>
XML;
    }
}

