The Go standard library's `encoding/xml` package is generally safer than many XML parsers in other languages because it doesn't process external entities by default. However, Go applications often use third-party XML libraries for advanced features, and these can be vulnerable to XXE attacks including parameter entity attacks.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/xml"
	"fmt"
	"io/ioutil"
	"net/http"
	"os/exec"
	"strings"

	"github.com/beevik/etree"
)

type Config struct {
	Database string `xml:"database"`
	Host     string `xml:"host"`
	Port     int    `xml:"port"`
}

func uploadConfig(w http.ResponseWriter, r *http.Request) {
	// Read uploaded XML file
	file, _, err := r.FormFile("config")
	if err != nil {
		http.Error(w, "Failed to read file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	xmlData, err := ioutil.ReadAll(file)
	if err != nil {
		http.Error(w, "Failed to read XML", http.StatusBadRequest)
		return
	}

	// VULNERABLE: Using etree without disabling external entities
	doc := etree.NewDocument()
	if err := doc.ReadFromBytes(xmlData); err != nil {
		http.Error(w, "Invalid XML", http.StatusBadRequest)
		return
	}

	// Process configuration
	root := doc.Root()
	if root != nil {
		database := root.FindElement("database")
		if database != nil {
			fmt.Fprintf(w, "Database: %s\n", database.Text())
		}
	}
}

func main() {
	http.HandleFunc("/upload", uploadConfig)
	http.ListenAndServe(":8080", nil)
}
```

