**Why This Is Dangerous**:
- Parameter entities (%entity;) are evaluated in the DTD before the document is parsed, bypassing many XXE protections
- Out-of-band exfiltration sends data to attacker-controlled servers, working even when responses aren't returned to the user
- Can read arbitrary files from the server including /etc/passwd, /etc/shadow, application configs, private keys
- Enables Server-Side Request Forgery (SSRF) to scan internal networks
- Recursive entity expansion can cause denial of service (Billion Laughs attack)

**SECURE VERSION**:

```go
package main

import (
	"bytes"
	"encoding/xml"
	"fmt"
	"io"
	"net/http"
	"regexp"
	"strings"
)

const maxXMLSize = 1 * 1024 * 1024 // 1MB limit

type Config struct {
	XMLName  xml.Name `xml:"config"`
	Database string   `xml:"database"`
	Host     string   `xml:"host"`
	Port     int      `xml:"port"`
}

// containsDTD checks for DOCTYPE declarations which enable XXE
func containsDTD(data []byte) bool {
	// Check for DOCTYPE declaration (case-insensitive)
	dtdPattern := regexp.MustCompile(`(?i)<!DOCTYPE`)
	entityPattern := regexp.MustCompile(`(?i)<!ENTITY`)
	systemPattern := regexp.MustCompile(`(?i)SYSTEM\s+["']`)
	publicPattern := regexp.MustCompile(`(?i)PUBLIC\s+["']`)

	return dtdPattern.Match(data) ||
		entityPattern.Match(data) ||
		systemPattern.Match(data) ||
		publicPattern.Match(data)
}

func uploadConfigSecure(w http.ResponseWriter, r *http.Request) {
	// Limit request size to prevent DoS
	r.Body = http.MaxBytesReader(w, r.Body, maxXMLSize)

	file, _, err := r.FormFile("config")
	if err != nil {
		http.Error(w, "Failed to read file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	// Read with size limit
	xmlData, err := io.ReadAll(io.LimitReader(file, maxXMLSize))
	if err != nil {
		http.Error(w, "Failed to read XML", http.StatusBadRequest)
		return
	}

	// SECURITY: Reject any XML with DTD declarations
	if containsDTD(xmlData) {
		http.Error(w, "XML with DTD declarations not allowed", http.StatusBadRequest)
		return
	}

	// SECURE: Use Go's encoding/xml which doesn't process external entities
	var config Config
	decoder := xml.NewDecoder(bytes.NewReader(xmlData))

	// Disable entity expansion
	decoder.Strict = true
	decoder.Entity = nil // Don't resolve any entities

	if err := decoder.Decode(&config); err != nil {
		http.Error(w, "Invalid XML structure", http.StatusBadRequest)
		return
	}

	// Validate parsed values
	if !isValidDatabaseName(config.Database) {
		http.Error(w, "Invalid database name", http.StatusBadRequest)
		return
	}

	fmt.Fprintf(w, "Database: %s, Host: %s, Port: %d\n",
		config.Database, config.Host, config.Port)
}

func isValidDatabaseName(name string) bool {
	validPattern := regexp.MustCompile(`^[a-zA-Z][a-zA-Z0-9_]{0,63}$`)
	return validPattern.MatchString(name)
}

func main() {
	http.HandleFunc("/upload", uploadConfigSecure)
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **DTD Detection**: Rejects any XML containing DOCTYPE, ENTITY, SYSTEM, or PUBLIC declarations before parsing
- **Safe Parser**: Uses Go's encoding/xml with Strict mode and Entity set to nil to prevent entity resolution
- **Size Limits**: MaxBytesReader and LimitReader prevent memory exhaustion attacks
- **Input Validation**: Validates parsed values against strict patterns after successful parsing

When you need advanced XML processing for SOAP services or complex XML schemas, you must implement multiple defense layers since third-party libraries may have varying levels of XXE protection.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"encoding/xml"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"os"
	"regexp"
	"strings"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

// Configuration constants
const (
	maxXMLSize       = 5 * 1024 * 1024  // 5MB
	maxElementDepth  = 50               // Prevent deeply nested attacks
	maxAttributes    = 100              // Prevent attribute-based DoS
	parseTimeout     = 30 * time.Second
)

// SecurityLogger provides structured security event logging
type SecurityLogger struct {
	logger *slog.Logger
}

func NewSecurityLogger() *SecurityLogger {
	return &SecurityLogger{
		logger: slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
			Level: slog.LevelInfo,
		})),
	}
}

func (sl *SecurityLogger) LogXXEAttempt(ip, pattern, payload string) {
	sl.logger.Warn("XXE_ATTACK_DETECTED",
		slog.String("source_ip", ip),
		slog.String("pattern_matched", pattern),
		slog.String("payload_snippet", truncatePayload(payload, 200)),
		slog.Time("timestamp", time.Now().UTC()),
	)
}

func (sl *SecurityLogger) LogParseSuccess(ip string, documentSize int) {
	sl.logger.Info("XML_PARSE_SUCCESS",
		slog.String("source_ip", ip),
		slog.Int("document_size", documentSize),
	)
}

func truncatePayload(s string, maxLen int) string {
	if len(s) > maxLen {
		return s[:maxLen] + "...[truncated]"
	}
	return s
}

// XXEDetector implements multi-layer XXE detection
type XXEDetector struct {
	patterns []*regexp.Regexp
	mu       sync.RWMutex
}

func NewXXEDetector() *XXEDetector {
	patterns := []string{
		// DOCTYPE declarations
		`(?i)<!DOCTYPE\s`,
		// General entities
		`(?i)<!ENTITY\s`,
		// Parameter entities (the most dangerous for OOB exfiltration)
		`(?i)<!ENTITY\s+%`,
		`%[a-zA-Z][a-zA-Z0-9]*;`,
		// External entity references
		`(?i)SYSTEM\s+["'][^"']*["']`,
		`(?i)PUBLIC\s+["'][^"']*["']`,
		// XInclude attacks
		`(?i)<xi:include`,
		`(?i)xmlns:xi\s*=`,
		// CDATA with suspicious content
		`(?i)<!\[CDATA\[.*?<!`,
		// URL-based entity expansion
		`(?i)file://`,
		`(?i)http://`,
		`(?i)https://`,
		`(?i)ftp://`,
		`(?i)gopher://`,
		`(?i)dict://`,
		`(?i)php://`,
		`(?i)jar://`,
		`(?i)netdoc://`,
	}

	compiled := make([]*regexp.Regexp, len(patterns))
	for i, p := range patterns {
		compiled[i] = regexp.MustCompile(p)
	}

	return &XXEDetector{patterns: compiled}
}

func (d *XXEDetector) Detect(data []byte) (bool, string) {
	d.mu.RLock()
	defer d.mu.RUnlock()

	for _, pattern := range d.patterns {
		if pattern.Match(data) {
			return true, pattern.String()
		}
	}
	return false, ""
}

// SafeXMLParser wraps xml.Decoder with security controls
type SafeXMLParser struct {
	detector *XXEDetector
	logger   *SecurityLogger
	limiter  *rate.Limiter
}

func NewSafeXMLParser() *SafeXMLParser {
	return &SafeXMLParser{
		detector: NewXXEDetector(),
		logger:   NewSecurityLogger(),
		limiter:  rate.NewLimiter(rate.Limit(100), 10), // 100 req/sec, burst 10
	}
}

func (p *SafeXMLParser) Parse(ctx context.Context, r io.Reader, v interface{}, clientIP string) error {
	// Layer 1: Rate limiting
	if !p.limiter.Allow() {
		return errors.New("rate limit exceeded")
	}

	// Layer 2: Read with size limit
	limitedReader := io.LimitReader(r, maxXMLSize)
	data, err := io.ReadAll(limitedReader)
	if err != nil {
		return fmt.Errorf("failed to read XML: %w", err)
	}

	// Layer 3: Pre-parse XXE detection
	if detected, pattern := p.detector.Detect(data); detected {
		p.logger.LogXXEAttempt(clientIP, pattern, string(data))
		return errors.New("XML contains prohibited patterns")
	}

	// Layer 4: Sanitize XML (remove any XML declarations with encodings that could bypass)
	data = sanitizeXMLDeclaration(data)

	// Layer 5: Parse with timeout
	parseDone := make(chan error, 1)
	go func() {
		decoder := xml.NewDecoder(bytes.NewReader(data))
		decoder.Strict = true
		decoder.Entity = nil // Disable all entity resolution

		// Custom token handler to enforce depth limits
		if err := parseWithDepthLimit(decoder, v, maxElementDepth); err != nil {
			parseDone <- err
			return
		}
		parseDone <- nil
	}()

	select {
	case err := <-parseDone:
		if err != nil {
			return fmt.Errorf("XML parse error: %w", err)
		}
		p.logger.LogParseSuccess(clientIP, len(data))
		return nil
	case <-ctx.Done():
		return errors.New("XML parsing timeout")
	case <-time.After(parseTimeout):
		return errors.New("XML parsing timeout")
	}
}

func sanitizeXMLDeclaration(data []byte) []byte {
	// Remove potentially malicious encoding declarations
	declPattern := regexp.MustCompile(`<\?xml[^?]*\?>`)
	return declPattern.ReplaceAll(data, []byte(`<?xml version="1.0" encoding="UTF-8"?>`))
}

func parseWithDepthLimit(decoder *xml.Decoder, v interface{}, maxDepth int) error {
	depth := 0
	for {
		tok, err := decoder.Token()
		if err == io.EOF {
			break
		}
		if err != nil {
			return err
		}

		switch tok.(type) {
		case xml.StartElement:
			depth++
			if depth > maxDepth {
				return errors.New("XML document exceeds maximum nesting depth")
			}
		case xml.EndElement:
			depth--
		}
	}

	// Re-parse with the actual struct after validation
	return xml.Unmarshal(decoder.InputOffset().([]byte), v)
}

// SOAP Service Example
type SOAPEnvelope struct {
	XMLName xml.Name    `xml:"Envelope"`
	Body    SOAPBody    `xml:"Body"`
}

type SOAPBody struct {
	Content string `xml:",innerxml"`
}

type SOAPRequest struct {
	Action string `xml:"action"`
	Data   string `xml:"data"`
}

func (p *SafeXMLParser) HandleSOAPRequest(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), parseTimeout)
	defer cancel()

	clientIP := r.RemoteAddr
	if forwarded := r.Header.Get("X-Forwarded-For"); forwarded != "" {
		clientIP = strings.Split(forwarded, ",")[0]
	}

	var envelope SOAPEnvelope
	if err := p.Parse(ctx, r.Body, &envelope, clientIP); err != nil {
		http.Error(w, "Invalid SOAP request", http.StatusBadRequest)
		return
	}

	// Process the validated SOAP request
	w.Header().Set("Content-Type", "application/soap+xml")
	fmt.Fprintf(w, `<?xml version="1.0"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <Response>Request processed successfully</Response>
  </soap:Body>
</soap:Envelope>`)
}

func main() {
	parser := NewSafeXMLParser()

	mux := http.NewServeMux()
	mux.HandleFunc("/soap", parser.HandleSOAPRequest)

	server := &http.Server{
		Addr:         ":8080",
		Handler:      mux,
		ReadTimeout:  30 * time.Second,
		WriteTimeout: 30 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	fmt.Println("Starting secure XML service on :8080")
	if err := server.ListenAndServe(); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}
