**Why This Is Dangerous**:
- The payload expands from ~1KB to ~3GB in memory (10^9 "lol" strings)
- Each entity reference multiplies by 10, creating exponential growth
- Server runs out of memory causing OutOfMemoryError and crash
- A single malicious request can take down the entire application
- Default Java XML parsers process DTDs and entities by default

**SECURE VERSION**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.XMLConstants;
import org.w3c.dom.Document;
import java.io.InputStream;
import java.util.logging.Logger;

public class SecureXmlProcessor {
    private static final Logger logger = Logger.getLogger(SecureXmlProcessor.class.getName());
    private final DocumentBuilderFactory factory;

    public SecureXmlProcessor() throws Exception {
        factory = DocumentBuilderFactory.newInstance();

        // CRITICAL: Disable DTDs entirely (most secure option)
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Additional protections if DTDs are needed
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Disable XInclude processing
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        // Set secure processing feature
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // Limit entity expansion (defense in depth)
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
    }

    public Document parseXmlDocument(InputStream xmlInput) throws Exception {
        try {
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(xmlInput);
            logger.info("XML document parsed successfully");
            return document;
        } catch (Exception e) {
            logger.warning("XML parsing failed: " + e.getMessage());
            throw new SecurityException("Invalid XML document", e);
        }
    }
}
```

**Key Security Controls**:
- `disallow-doctype-decl`: Completely blocks DTD processing, preventing all entity expansion attacks
- `FEATURE_SECURE_PROCESSING`: Enables parser-level security limits on entity expansion
- `setExpandEntityReferences(false)`: Prevents automatic entity expansion during parsing
- Custom error handling prevents information leakage about parser internals

When DTD processing is required for legitimate business needs, you need a multi-layered defense strategy that limits entity expansion while still allowing valid schemas. This is common in financial services (FIXML), healthcare (HL7), and supply chain (EDI/XML) integrations.

**PRODUCTION PATTERN**:

```java
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.SAXParserFactory;
import javax.xml.XMLConstants;
import org.w3c.dom.Document;
import org.xml.sax.SAXException;
import org.xml.sax.InputSource;
import org.xml.sax.XMLReader;
import org.xml.sax.helpers.DefaultHandler;
import java.io.InputStream;
import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.util.concurrent.*;
import java.util.logging.Logger;

public class ProductionXmlProcessor {
    private static final Logger logger = Logger.getLogger(ProductionXmlProcessor.class.getName());

    // Entity expansion limits
    private static final int MAX_ENTITY_EXPANSIONS = 100;
    private static final int MAX_ENTITY_SIZE_LIMIT = 64000; // 64KB per entity
    private static final int MAX_TOTAL_ENTITY_SIZE = 10_000_000; // 10MB total
    private static final long MAX_PARSE_TIME_MS = 30_000; // 30 seconds timeout
    private static final int MAX_XML_SIZE_BYTES = 50_000_000; // 50MB max file

    private final DocumentBuilderFactory documentFactory;
    private final SAXParserFactory saxFactory;
    private final ExecutorService parseExecutor;

    public ProductionXmlProcessor() throws Exception {
        // Configure DocumentBuilderFactory with entity limits
        documentFactory = DocumentBuilderFactory.newInstance();
        configureSecureFactory(documentFactory);

        // Configure SAX for pre-validation
        saxFactory = SAXParserFactory.newInstance();
        configureSaxFactory(saxFactory);

        // Thread pool for timeout enforcement
        parseExecutor = Executors.newFixedThreadPool(4, r -> {
            Thread t = new Thread(r, "xml-parser");
            t.setDaemon(true);
            return t;
        });
    }

    private void configureSecureFactory(DocumentBuilderFactory factory) throws Exception {
        // Enable secure processing with limits
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // Disable external entities (prevents SSRF attacks)
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Block external DTD and schema access
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        // JDK-specific entity expansion limits (Java 8+)
        System.setProperty("jdk.xml.entityExpansionLimit", String.valueOf(MAX_ENTITY_EXPANSIONS));
        System.setProperty("jdk.xml.maxGeneralEntitySizeLimit", String.valueOf(MAX_ENTITY_SIZE_LIMIT));
        System.setProperty("jdk.xml.totalEntitySizeLimit", String.valueOf(MAX_TOTAL_ENTITY_SIZE));
        System.setProperty("jdk.xml.entityReplacementLimit", String.valueOf(MAX_ENTITY_EXPANSIONS * 10));
    }

    private void configureSaxFactory(SAXParserFactory factory) throws Exception {
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
    }

    public Document parseXmlDocument(InputStream xmlInput, String requestId) throws Exception {
        logger.info(String.format("[%s] Starting XML parsing", requestId));

        // Layer 1: Size limit check
        byte[] xmlBytes = readWithSizeLimit(xmlInput, MAX_XML_SIZE_BYTES, requestId);

        // Layer 2: Pre-validation with SAX (fast rejection of malicious XML)
        preValidateWithSax(new ByteArrayInputStream(xmlBytes), requestId);

        // Layer 3: Parse with timeout protection
        Future<Document> parseTask = parseExecutor.submit(() -> {
            DocumentBuilder builder = documentFactory.newDocumentBuilder();
            builder.setErrorHandler(new StrictErrorHandler(requestId));
            return builder.parse(new ByteArrayInputStream(xmlBytes));
        });

        try {
            Document doc = parseTask.get(MAX_PARSE_TIME_MS, TimeUnit.MILLISECONDS);
            logger.info(String.format("[%s] XML parsing completed successfully", requestId));
            return doc;
        } catch (TimeoutException e) {
            parseTask.cancel(true);
            logger.severe(String.format("[%s] XML parsing timeout - possible DoS attack", requestId));
            throw new SecurityException("XML parsing timeout exceeded");
        } catch (ExecutionException e) {
            logger.warning(String.format("[%s] XML parsing error: %s", requestId, e.getCause().getMessage()));
            throw new SecurityException("XML parsing failed", e.getCause());
        }
    }

    private byte[] readWithSizeLimit(InputStream input, int maxSize, String requestId) throws Exception {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        byte[] chunk = new byte[8192];
        int bytesRead;
        int totalBytes = 0;

        while ((bytesRead = input.read(chunk)) != -1) {
            totalBytes += bytesRead;
            if (totalBytes > maxSize) {
                logger.warning(String.format("[%s] XML size limit exceeded: %d bytes", requestId, totalBytes));
                throw new SecurityException("XML document exceeds maximum allowed size");
            }
            buffer.write(chunk, 0, bytesRead);
        }

        logger.fine(String.format("[%s] XML size: %d bytes", requestId, totalBytes));
        return buffer.toByteArray();
    }

    private void preValidateWithSax(InputStream xmlInput, String requestId) throws Exception {
        XMLReader reader = saxFactory.newSAXParser().getXMLReader();

        // Count entity expansions during parse
        EntityExpansionCounter handler = new EntityExpansionCounter(MAX_ENTITY_EXPANSIONS, requestId);
        reader.setContentHandler(handler);
        reader.setEntityResolver((publicId, systemId) -> {
            logger.warning(String.format("[%s] Blocked external entity: %s", requestId, systemId));
            return new InputSource(new ByteArrayInputStream(new byte[0]));
        });

        try {
            reader.parse(new InputSource(xmlInput));
        } catch (EntityLimitExceededException e) {
            logger.severe(String.format("[%s] Entity expansion limit exceeded - billion laughs attack detected", requestId));
            throw new SecurityException("Suspicious entity expansion detected");
        }
    }

    // Custom exception for entity limit violations
    private static class EntityLimitExceededException extends SAXException {
        public EntityLimitExceededException(String message) {
            super(message);
        }
    }

    // Entity expansion counter handler
    private static class EntityExpansionCounter extends DefaultHandler {
        private int expansionCount = 0;
        private final int maxExpansions;
        private final String requestId;

        public EntityExpansionCounter(int maxExpansions, String requestId) {
            this.maxExpansions = maxExpansions;
            this.requestId = requestId;
        }

        @Override
        public void characters(char[] ch, int start, int length) throws SAXException {
            expansionCount++;
            if (expansionCount > maxExpansions) {
                throw new EntityLimitExceededException(
                    String.format("Entity expansion limit (%d) exceeded", maxExpansions));
            }
        }
    }

    // Strict error handler that fails on any warnings
    private static class StrictErrorHandler implements org.xml.sax.ErrorHandler {
        private final String requestId;

        public StrictErrorHandler(String requestId) {
            this.requestId = requestId;
        }

        @Override
        public void warning(org.xml.sax.SAXParseException e) throws SAXException {
            Logger.getLogger(ProductionXmlProcessor.class.getName())
                .warning(String.format("[%s] XML warning: %s", requestId, e.getMessage()));
        }

        @Override
        public void error(org.xml.sax.SAXParseException e) throws SAXException {
            throw new SAXException("XML parsing error", e);
        }

        @Override
        public void fatalError(org.xml.sax.SAXParseException e) throws SAXException {
            throw new SAXException("Fatal XML parsing error", e);
        }
    }

    public void shutdown() {
        parseExecutor.shutdownNow();
    }
}
```

