using System.IO;
using System.Xml;
using Microsoft.AspNetCore.Mvc;

namespace VulnerableApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class ConfigController : ControllerBase
    {
        [HttpPost("upload")]
        public IActionResult UploadConfig()
        {
            using var reader = new StreamReader(Request.Body);
            string xmlContent = reader.ReadToEnd();

            // VULNERABLE: Default XmlDocument allows DTD processing
            XmlDocument doc = new XmlDocument();
            doc.LoadXml(xmlContent);

            // Even if we don't return XML content, blind XXE still works
            string configName = doc.SelectSingleNode("//name")?.InnerText ?? "Unknown";

            return Ok(new { message = $"Configuration '{configName}' processed successfully" });
        }

        [HttpPost("validate")]
        public IActionResult ValidateConfig()
        {
            using var reader = new StreamReader(Request.Body);
            string xmlContent = reader.ReadToEnd();

            // VULNERABLE: XmlReader with insecure settings
            XmlReaderSettings settings = new XmlReaderSettings();
            settings.DtdProcessing = DtdProcessing.Parse; // Dangerous!
            settings.XmlResolver = new XmlUrlResolver(); // Allows external entities

            using var stringReader = new StringReader(xmlContent);
            using var xmlReader = XmlReader.Create(stringReader, settings);

            while (xmlReader.Read()) { }

            return Ok(new { valid = true });
