**SECURE VERSION**:

```csharp
using System;
using System.IO;
using System.Xml;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace SecureApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class ConfigController : ControllerBase
    {
        private readonly ILogger<ConfigController> _logger;

        public ConfigController(ILogger<ConfigController> logger)
        {
            _logger = logger;
        }

        [HttpPost("upload")]
        public IActionResult UploadConfig()
        {
            try
            {
                using var reader = new StreamReader(Request.Body);
                string xmlContent = reader.ReadToEnd();

                // SECURE: Create XmlDocument with secure settings
                XmlDocument doc = new XmlDocument();
                doc.XmlResolver = null; // Disable external entity resolution

                // Use secure XmlReaderSettings for additional protection
                XmlReaderSettings settings = CreateSecureXmlSettings();

                using var stringReader = new StringReader(xmlContent);
                using var xmlReader = XmlReader.Create(stringReader, settings);

                doc.Load(xmlReader);

                string configName = doc.SelectSingleNode("//name")?.InnerText ?? "Unknown";

                _logger.LogInformation("Configuration processed: {ConfigName} from {IP}", 
                    configName, HttpContext.Connection.RemoteIpAddress);

                return Ok(new { message = $"Configuration '{configName}' processed successfully" });
            }
            catch (XmlException ex)
            {
                _logger.LogWarning("Invalid XML received from {IP}: {Error}", 
                    HttpContext.Connection.RemoteIpAddress, ex.Message);
                return BadRequest(new { error = "Invalid XML format" });
            }
        }

        private static XmlReaderSettings CreateSecureXmlSettings()
        {
            return new XmlReaderSettings
            {
                DtdProcessing = DtdProcessing.Prohibit, // Block DTD entirely
                XmlResolver = null, // No external entity resolution
                MaxCharactersFromEntities = 1024, // Limit entity expansion
                MaxCharactersInDocument = 1024 * 1024 // 1MB max document size
            };
        }
    }
}
```

**Key Security Controls**:
- **DtdProcessing.Prohibit**: Completely blocks DTD processing, preventing all XXE variants
- **XmlResolver = null**: Disables resolution of external entities even if DTD processing were allowed
- **MaxCharactersFromEntities**: Prevents "Billion Laughs" denial of service attacks
- **MaxCharactersInDocument**: Limits overall document size to prevent resource exhaustion

This is a common enterprise scenario where you need DTD/schema validation but must prevent XXE attacks. The solution involves creating a custom XmlResolver that only allows trusted, local schemas while blocking all external entity resolution.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.IO;
using System.Net;
using System.Xml;
using System.Xml.Schema;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.AspNetCore.RateLimiting;

namespace SecureApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class SecureXmlController : ControllerBase
    {
        private readonly ILogger<SecureXmlController> _logger;
        private readonly IXmlSecurityService _xmlSecurityService;

        public SecureXmlController(
            ILogger<SecureXmlController> logger,
            IXmlSecurityService xmlSecurityService)
        {
            _logger = logger;
            _xmlSecurityService = xmlSecurityService;
        }

        [HttpPost("validate")]
        [EnableRateLimiting("xml-upload")]
        public IActionResult ValidateWithSchema()
        {
            var clientIp = HttpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown";

            try
            {
                using var reader = new StreamReader(Request.Body);
                string xmlContent = reader.ReadToEnd();

                // Pre-validation: Check for suspicious patterns
                if (_xmlSecurityService.ContainsSuspiciousPatterns(xmlContent))
                {
                    _logger.LogWarning(
                        "XXE attack attempt detected from {IP}. Content length: {Length}",
                        clientIp, xmlContent.Length);

                    // Don't reveal detection to attacker
                    return BadRequest(new { error = "Invalid XML format" });
                }

                var result = _xmlSecurityService.ParseAndValidate(xmlContent);

                _logger.LogInformation(
                    "XML validated successfully from {IP}. Schema: {Schema}",
                    clientIp, result.SchemaUsed);

                return Ok(new { 
                    valid = true, 
                    documentRoot = result.RootElement,
                    validationMessages = result.Warnings
                });
            }
            catch (XmlSecurityException ex)
            {
                _logger.LogWarning(
                    "XML security violation from {IP}: {Reason}",
                    clientIp, ex.Reason);

                return BadRequest(new { error = "XML processing error" });
            }
            catch (XmlSchemaValidationException ex)
            {
                _logger.LogInformation(
                    "XML schema validation failed from {IP}: {Message}",
                    clientIp, ex.Message);

                return BadRequest(new { error = "Schema validation failed", details = ex.Message });
            }
        }
    }

    public interface IXmlSecurityService
    {
        bool ContainsSuspiciousPatterns(string xml);
        XmlParseResult ParseAndValidate(string xml);
    }

    public class XmlSecurityService : IXmlSecurityService
    {
        private readonly ILogger<XmlSecurityService> _logger;
        private readonly string _trustedSchemaPath;
        private readonly HashSet<string> _allowedSchemaNames;

        public XmlSecurityService(ILogger<XmlSecurityService> logger)
        {
            _logger = logger;
            _trustedSchemaPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "Schemas");
            _allowedSchemaNames = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "config.xsd",
                "product.xsd",
                "order.xsd"
            };
        }

        public bool ContainsSuspiciousPatterns(string xml)
        {
            // Block common XXE patterns before parsing
            string[] dangerousPatterns = new[]
            {
                "<!ENTITY",
                "SYSTEM",
                "PUBLIC",
                "file://",
                "file:\\\\",
                "http://",
                "https://",
                "ftp://",
                "gopher://",
                "expect://",
                "php://"
            };

            string upperXml = xml.ToUpperInvariant();
            foreach (var pattern in dangerousPatterns)
            {
                if (upperXml.Contains(pattern.ToUpperInvariant()))
                {
                    return true;
                }
            }

            return false;
        }

        public XmlParseResult ParseAndValidate(string xml)
        {
            var result = new XmlParseResult();
            var warnings = new List<string>();

            // Create settings with custom secure resolver
            XmlReaderSettings settings = new XmlReaderSettings
            {
                DtdProcessing = DtdProcessing.Parse, // Allow DTD for schema reference
                ValidationType = ValidationType.Schema,
                XmlResolver = new SecureLocalXmlResolver(_trustedSchemaPath, _allowedSchemaNames),
                MaxCharactersFromEntities = 0, // No entity expansion allowed
                MaxCharactersInDocument = 5 * 1024 * 1024 // 5MB max
            };

            settings.ValidationEventHandler += (sender, e) =>
            {
                if (e.Severity == XmlSeverityType.Warning)
                    warnings.Add(e.Message);
                else
                    throw new XmlSchemaValidationException(e.Message);
            };

            using var stringReader = new StringReader(xml);
            using var xmlReader = XmlReader.Create(stringReader, settings);

            XmlDocument doc = new XmlDocument();
            doc.XmlResolver = new SecureLocalXmlResolver(_trustedSchemaPath, _allowedSchemaNames);
            doc.Load(xmlReader);

            result.RootElement = doc.DocumentElement?.Name ?? "unknown";
            result.Warnings = warnings;
            result.SchemaUsed = "local-trusted";

            return result;
        }
    }

    /// <summary>
    /// Custom XmlResolver that ONLY allows loading schemas from a trusted local directory.
    /// All external URLs and file system paths outside the trusted directory are blocked.
    /// </summary>
    public class SecureLocalXmlResolver : XmlResolver
    {
        private readonly string _trustedBasePath;
        private readonly HashSet<string> _allowedSchemaNames;

        public SecureLocalXmlResolver(string trustedBasePath, HashSet<string> allowedSchemaNames)
        {
            _trustedBasePath = Path.GetFullPath(trustedBasePath);
            _allowedSchemaNames = allowedSchemaNames;
        }

        public override ICredentials Credentials
        {
            set { /* Ignore - we don't use credentials */ }
        }

        public override Uri ResolveUri(Uri baseUri, string relativeUri)
        {
            // Only allow resolution of known schema names
            if (string.IsNullOrEmpty(relativeUri))
                throw new XmlSecurityException("Empty URI not allowed", "empty_uri");

            string fileName = Path.GetFileName(relativeUri);

            if (!_allowedSchemaNames.Contains(fileName))
                throw new XmlSecurityException($"Schema not in allowlist: {fileName}", "schema_blocked");

            string fullPath = Path.GetFullPath(Path.Combine(_trustedBasePath, fileName));

            // Path traversal protection
            if (!fullPath.StartsWith(_trustedBasePath, StringComparison.OrdinalIgnoreCase))
                throw new XmlSecurityException("Path traversal attempt detected", "path_traversal");

            if (!File.Exists(fullPath))
                throw new XmlSecurityException($"Schema file not found: {fileName}", "schema_not_found");

            return new Uri(fullPath);
        }

        public override object GetEntity(Uri absoluteUri, string role, Type ofObjectToReturn)
        {
            // Block all non-file URIs (http, https, ftp, etc.)
            if (absoluteUri.Scheme != "file")
                throw new XmlSecurityException(
                    $"External URI scheme blocked: {absoluteUri.Scheme}", 
                    "external_uri_blocked");

            string localPath = absoluteUri.LocalPath;
            string fullPath = Path.GetFullPath(localPath);

            // Verify path is within trusted directory
            if (!fullPath.StartsWith(_trustedBasePath, StringComparison.OrdinalIgnoreCase))
                throw new XmlSecurityException(
                    "Access to path outside trusted directory blocked", 
                    "path_escape_blocked");

            // Verify file is in allowlist
            string fileName = Path.GetFileName(fullPath);
            if (!_allowedSchemaNames.Contains(fileName))
                throw new XmlSecurityException(
                    $"File not in allowlist: {fileName}", 
                    "file_blocked");

            return File.OpenRead(fullPath);
        }
    }

    public class XmlSecurityException : Exception
    {
        public string Reason { get; }

        public XmlSecurityException(string message, string reason) : base(message)
        {
            Reason = reason;
        }
    }

    public class XmlParseResult
    {
        public string RootElement { get; set; }
        public string SchemaUsed { get; set; }
        public List<string> Warnings { get; set; } = new List<string>();
    }
}
